import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: { day: string; icon: string; high: number; low: number }[]; // 5-day forecast array
}

function useComponent(props: Props) {
  const [unit, setUnit] = useState(props.unit);

  const toggleUnit = useCallback(() => {
    setUnit((prev) => (prev === 'C' ? 'F' : 'C'));
  }, []);

  return { unit, toggleUnit };
}

export default function Component(props: Props) {
  const { unit, toggleUnit } = useComponent(props);

  // Map common weather conditions to built-in icons
  const getIconName = (condition: string): string => {
    const c = condition.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return 'user'; // Using 'user' as sun/clear icon
    if (c.includes('cloud')) return 'settings'; // Using 'settings' as cloud icon
    if (c.includes('rain') || c.includes('storm')) return 'plus'; // Using 'plus' as rain icon
    return 'menu'; // Default
  };

  return (
    <Card padding={24} shadow="md" style={{ width: '100%', maxWidth: 400 }}>
      <Stack gap={16} align="stretch">
        <Row justify="between" align="center">
          <Heading level={3}>{props.city}</Heading>
          <Button variant="ghost" size="sm" onClick={toggleUnit}>°{unit}</Button>
        </Row>
        <Stack align="center" gap={8}>
          <Heading level={1} style={{ fontSize: 'var(--ggui-font-size-4xl)' }}>{props.temperature}°{unit}</Heading>
          <Row align="center" gap={8} style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            <Icon name={getIconName(props.condition)} size={20} />
            <Text variant="label">{props.condition}</Text>
          </Row>
        </Stack>
        <Row justify="center" gap={24}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="bodySmall" style={{ fontWeight: 600 }}>{props.humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text variant="bodySmall" style={{ fontWeight: 600 }}>{props.windSpeed} km/h</Text>
          </Stack>
        </Row>
        <Divider />
        <Row justify="between" gap={12} style={{ overflowX: 'auto' }}>
          {props.forecast.map((f, i) => (
            <Stack key={i} align="center" gap={8} style={{ minWidth: 48 }}>
              <Text variant="caption">{f.day}</Text>
              <Icon name={getIconName(f.icon)} size={20} />
              <Text variant="caption" style={{ fontWeight: 600 }}>{f.high}°/{f.low}°</Text>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (data: Record<string, unknown>) => void; // Action: Submit Survey
}

function useComponent(props: Props) {
  const handleSubmit = useCallback((data: Record<string, unknown>) => {
    props.onSubmit?.(data);
  }, [props.onSubmit]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', rating: '', interests: [] as string[], comments: '' });
  const [touched, setTouched] = useState({ name: false, email: false });
  const totalSteps = 5;

  const errors = useMemo(() => ({
    name: touched.name && !formData.name ? 'Name is required' : '',
    email: touched.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) ? 'Valid email is required' : ''
  }), [touched, formData]);

  const isValidStep1 = formData.name !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);

  const next = () => setStep(s => Math.min(s + 1, totalSteps));
  const back = () => setStep(s => Math.max(s - 1, 1));

  return { step, formData, setFormData, touched, setTouched, errors, isValidStep1, next, back, handleSubmit };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, touched, setTouched, errors, isValidStep1, next, back, handleSubmit } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Progress value={((step - 1) / 4) * 100} max={100} />
        <Text variant="label">Step {step} of 5</Text>

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={2}>Personal Info</Heading>
              <Input 
                label="Name" required={true} error={errors.name}
                value={formData.name} onChange={(v) => { setTouched(t => ({...t, name: true})); setFormData(f => ({...f, name: v})) }} placeholder="John Doe" />
              <Input 
                label="Email" required={true} error={errors.email}
                value={formData.email} onChange={(v) => { setTouched(t => ({...t, email: true})); setFormData(f => ({...f, email: v})) }} placeholder="john@example.com" />
            </Stack>
          )}
          {step === 2 && (
            <Stack gap={16}>
              <Heading level={2}>Satisfaction</Heading>
              <RadioGroup label="How satisfied are you?" value={formData.rating} onChange={(v) => setFormData(f => ({...f, rating: v}))} options={props.satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))} />
            </Stack>
          )}
          {step === 3 && (
            <Stack gap={16}>
              <Heading level={2}>Interests</Heading>
              {props.featureOptions.map(opt => (
                <Checkbox key={opt} label={opt} checked={formData.interests.includes(opt)} onChange={(c) => setFormData(f => ({...f, interests: c ? [...f.interests, opt] : f.interests.filter(i => i !== opt)}))} />
              ))}
            </Stack>
          )}
          {step === 4 && (
            <Stack gap={16}>
              <Heading level={2}>Feedback</Heading>
              <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData(f => ({...f, comments: v}))} maxLength={500} showCount />
            </Stack>
          )}
          {step === 5 && (
            <Stack gap={16}>
              <Heading level={2}>Review</Heading>
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {formData.name}</Text>
                <Text variant="body"><strong>Email:</strong> {formData.email}</Text>
                <Text variant="body"><strong>Rating:</strong> {formData.rating}</Text>
                <Text variant="body"><strong>Interests:</strong> {formData.interests.join(', ') || 'None'}</Text>
                <Text variant="body"><strong>Comments:</strong> {formData.comments || 'None'}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" gap={16} justify="end">
          {step > 1 && <Button variant="secondary" onClick={back}>Back</Button>}
          {step < 5 && (
            <Button 
              disabled={step === 1 && !isValidStep1}
              onClick={next}
            >
              Next
            </Button>
          )}
          {step === 5 && <Button variant="primary" onClick={() => handleSubmit(formData)}>Submit</Button>}
        </Stack>
      </Stack>
    </Container>
  );
}

