import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: { id?: string; name?: string }[]; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');

  const completedCount = useMemo(() => tasks.filter(t => t.column === 'done').length, [tasks]);

  const moveTask = (taskId: string, columnId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: columnId } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'MOVE_TASK', taskId, columnId });
  };

  const addTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTaskTitle,
      priority: 'medium',
      assignee: '??',
      column: columnId,
      dueDate: new Date().toISOString().split('T')[0]
    };
    setTasks([...tasks, newTask]);
    setAddingTo(null);
    setNewTaskTitle('');
    handleTaskUpdate({ type: 'ADD_TASK', task: newTask });
  };

  return { tasks, columns: props.columns, completedCount, moveTask, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, addTask };
}

export default function Component(props: Props) {
  const { tasks, columns, completedCount, moveTask, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, addTask } = useComponent(props);

  // Ensure columns have IDs for rendering
  const safeColumns = columns.map(c => ({ id: c.id || '', name: c.name || '' }));

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Badge variant="primary">{completedCount} / {tasks.length} tasks completed</Badge>
        </Row>
        <Row align="start" gap={16} wrap>
          {safeColumns.map((col, idx) => (
            <Box key={col.id || idx} background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={12} style={{ flex: 1, minWidth: 300 }}>
              <Stack gap={16}>
                <Row justify="between" align="center">
                  <Heading level={4}>{col.name}</Heading>
                  <Badge>{tasks.filter(t => t.column === col.id).length}</Badge>
                </Row>
                <Stack gap={12}>
                  {tasks.filter(t => t.column === col.id).map((task) => (
                    <Card key={task.id} padding={16} shadow="sm">
                      <Stack gap={8}>
                        <Heading level={6}>{task.title}</Heading>
                        <Row justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'primary' : 'success'}>{task.priority}</Badge>
                          <Avatar name={task.assignee} size={24} />
                        </Row>
                        <Divider margin={8} />
                        <Select value={task.column} onChange={(val) => moveTask(task.id, val)} options={safeColumns.map(c => ({ value: c.id, label: `Move to ${c.name}` }))} />
                      </Stack>
                    </Card>
                  ))}
                  {addingTo === col.id ? (
                    <Card padding={16}>
                      <Stack gap={8}>
                        <Input label="Title" placeholder="Task title..." value={newTaskTitle} onChange={setNewTaskTitle} />
                        <Row gap={8}>
                          <Button size="sm" variant="primary" onClick={() => addTask(col.id)}>Add</Button>
                          <Button size="sm" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="ghost" fullWidth onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
                  )}
                </Stack>
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

