import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) => el.name.toLowerCase().includes(q) || el.symbol.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => {
    const cats = Array.from(new Set(props.elements.map((el) => el.category)));
    return cats.map((cat, i) => ({
      category: cat,
      color: `var(--ggui-color-primary-${(i % 9 + 1) * 100})`
    }));
  }, [props.elements]);

  const getCategoryColor = useCallback((category: string) => {
    return categories.find((c) => c.category === category)?.color || 'var(--ggui-color-surfaceVariant)';
  }, [categories]);

  return { searchQuery, setSearchQuery, selectedElement, setSelectedElement, filteredElements, categories, getCategoryColor };
}

export default function Component(props: Props) {
  const { searchQuery, setSearchQuery, selectedElement, setSelectedElement, filteredElements, categories, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <SearchField value={searchQuery} onChange={setSearchQuery} placeholder="Search by name or symbol..." />
        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {props.elements.map((el) => {
            const isVisible = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
            return (
              <Box key={el.atomicNumber} role="button" tabIndex={0} onClick={() => setSelectedElement(el)} onKeyDown={(e) => e.key === 'Enter' && setSelectedElement(el)} style={{ 
                gridRow: `${el.row} / span 1`,
                gridColumn: `${el.col} / span 1`,
                background: isVisible ? getCategoryColor(el.category) : 'var(--ggui-color-surfaceVariant)',
                opacity: isVisible ? 1 : 0.2,
                padding: 'var(--ggui-spacing-2)',
                borderRadius: 'var(--ggui-shape-radius-sm)',
                cursor: 'pointer',
                border: selectedElement?.atomicNumber === el.atomicNumber ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outlineVariant)',
                transition: 'all 200ms ease'
              }} aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`}>
                <Text variant="caption">{el.atomicNumber}</Text>
                <Heading level={6}>{el.symbol}</Heading>
              </Box>
            );
          })}
        </Box>
        <Stack direction="horizontal" gap={8} wrap>
          {categories.map((c) => <Tag key={c.category} style={{ backgroundColor: c.color, color: 'var(--ggui-color-onSurface)' }}>{c.category}</Tag>)}
        </Stack>
        {selectedElement && (
          <Card padding={24} shadow="md">
            <Heading level={2}>{selectedElement.name} ({selectedElement.symbol})</Heading>
            <Stack gap={8}>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

