import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = props.product.stock === 0;
  const stockStatus = props.product.stock > 5 ? 'In Stock' : 'Low Stock';
  const stockVariant = props.product.stock > 5 ? 'success' : 'warning';

  const handleAdd = () => {
    handleAddToCart({ productId: props.product.id, quantity });
  };

  return { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, stockStatus, stockVariant, handleAdd };
}

export default function Component(props: Props) {
  const { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, stockStatus, stockVariant, handleAdd } = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} align="start">
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="lg" padding={48} style={{ flex: '1' }}>
            <Heading level={3} align="center">{props.product.name}</Heading>
          </Box>
          <Stack gap={16} style={{ flex: '1' }}>
            <Heading level={1}>{props.product.name}</Heading>
            <Text variant="bodyLarge">{props.product.currency}{props.product.price.toFixed(2)}</Text>
            <Badge variant={stockVariant as any}>{stockStatus}</Badge>
            <Text variant="bodySmall">Rating: {props.product.rating}/5 ({props.product.reviewCount} reviews)</Text>

            <Divider />

            <Stack gap={8}>
              <Text variant="label">Quantity</Text>
              <Row gap={8}>
                <Button variant="outline" size="sm" onClick={() => setQuantity(q => Math.max(1, q - 1))}>-</Button>
                <Text variant="body" style={{ minWidth: '40px', textAlign: 'center' }}>{quantity}</Text>
                <Button variant="outline" size="sm" onClick={() => setQuantity(q => Math.min(props.product.stock, q + 1))}>+</Button>
              </Row>
              <Button variant="primary" disabled={isOutOfStock} onClick={handleAdd}>Add to Cart</Button>
            </Stack>
          </Stack>
        </Stack>

        <Tabs 
          items={[
            { key: 'description', label: 'Description', content: <Text>{props.product.description}</Text> },
            { key: 'specifications', label: 'Specifications', content: (
              <Table 
                columns={[{key: 'attr', header: 'Attribute'}, {key: 'val', header: 'Value'}]} 
                data={props.product.specifications.map((s: any) => ({ attr: s.name, val: s.value }))}
              />
            )},
            { key: 'reviews', label: 'Reviews', content: (
              <Stack gap={16}>
                {(props.product.reviews as any[]).map((r, i) => (
                  <Card key={i} padding={16}>
                    <Stack gap={4}>
                      <Text variant="label">{r.author} • {r.rating} stars</Text>
                      <Text variant="bodySmall">{r.comment}</Text>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            )}
          ]}
          activeKey={activeTab}
          onChange={setActiveTab}
        />
      </Stack>
    </Container>
  );
}

