// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: { sender: string; text: string; timestamp: string }[]; // Array of messages with sender name, text, and ISO timestamp
  onSendMessage?: (data: Record<string, unknown>) => void; // Action: Send Message
}

function useComponent(props: Props) {
  const handleSendMessage = useCallback((data: Record<string, unknown>) => {
    props.onSendMessage?.(data);
  }, [props.onSendMessage]);

  const [text, setText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [props.messages]);

  const onSend = () => {
    if (!text.trim()) return;
    handleSendMessage({ text, timestamp: new Date().toISOString() });
    setText('');
  };

  return { text, setText, onSend, scrollRef };
}

export default function Component(props: Props) {
  const { text, setText, onSend, scrollRef } = useComponent(props);

  return (
    <Stack as="main" style={{ height: '100vh', background: 'var(--ggui-color-surface)' }}>
      <header style={{ padding: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outline)', display: 'flex', alignItems: 'center' }}>
        <Heading level={3}>{props.title}</Heading>
        <Spacer size="flex" />
        <Badge variant="primary">{props.participantCount} participants</Badge>
      </header>
      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
        <Stack gap={12} aria-live="polite">
          {props.messages.map((m, i) => {
            const isOwn = m.sender === props.currentUser;
            const isGrouped = i > 0 && props.messages[i - 1].sender === m.sender;
            return (
            <Stack key={i} align={isOwn ? 'end' : 'start'}>
              {!isGrouped && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {m.sender} • {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </Text>
              )}
              <Card padding={12} shadow="sm" radius="md" style={{
                background: isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)',
                color: isOwn ? '#fff' : 'var(--ggui-color-onSurface)'
              }}>
                <Text>{m.text}</Text>
              </Card>
            </Stack>
            )})}
          <div ref={scrollRef} />
        </Stack>
      </Box>
      <form onSubmit={(e) => { e.preventDefault(); onSend(); }} style={{ padding: 'var(--ggui-spacing-4)', borderTop: '1px solid var(--ggui-color-outline)', display: 'flex', gap: 'var(--ggui-spacing-2)', alignItems: 'center' }}>
        <Input label="Message" value={text} onChange={setText} placeholder="Type a message..." style={{ flex: 1 }} />
        <Button type="submit" disabled={!text.trim()}>Send</Button>
      </form>
    </Stack>
  );
}

