// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile);
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validate = () => {
    const newErrors = { name: '', email: '' };
    if (!formData.name) newErrors.name = 'Name is required';
    if (!formData.email || !/^\S+@\S+\.\S+$/.test(formData.email)) newErrors.email = 'Valid email is required';
    setErrors(newErrors);
    return !newErrors.name && !newErrors.email;
  };

  const next = () => {
    if (step === 1 && !validate()) return;
    setStep((s) => Math.min(s + 1, 3));
  };

  const prev = () => setStep((s) => Math.max(s - 1, 1));

  const update = (key: string, value: any) => setFormData((prev) => ({ ...prev, [key]: value }));

  return { step, formData, errors, update, next, prev, handleComplete };
}

export default function Component(props: Props) {
  const { step, formData, errors, update, next, prev, handleComplete } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding Setup ({step}/3)</Heading>
        <Progress value={(step - 1) * 50} max={100} />

        {step === 1 && (
          <Stack gap={16}>
            <FormField label="Name" required error={errors.name}>
              <Input value={formData.name} onChange={(v) => update('name', v)} />
            </FormField>
            <FormField label="Email" required error={errors.email}>
              <Input type="email" value={formData.email} onChange={(v) => update('email', v)} />
            </FormField>
            <Text variant="label">Choose Avatar</Text>
            <Row gap={8}>
              {props.avatarOptions.map((opt) => (
                <Button key={opt} variant={formData.avatar === opt ? 'primary' : 'outline'} size="sm" onClick={() => update('avatar', opt)}>
                  {opt}
                </Button>
              ))}
            </Row>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <FormField label="Role">
              <Select value={formData.role} onChange={(v) => update('role', v)} options={props.roleOptions.map((r) => ({ value: r, label: r }))} />
            </FormField>
            <Box paddingY={8}>
              <Row align="center" gap={16} justify="between">
                <Text>Email Notifications</Text>
                <Toggle checked={formData.emailNotifications} onChange={(v) => update('emailNotifications', v)} />
              </Row>
            </Box>
            <Box paddingY={8}>
              <Row align="center" gap={16} justify="between">
                <Text>Dark Mode</Text>
                <Toggle 
                  checked={formData.theme === 'dark'} 
                  onChange={(checked) => update('theme', checked ? 'dark' : 'light')} 
                />
              </Row>
            </Box>
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Heading level={4}>Review</Heading>
            <Card padding={16}>
              <Stack gap={8}>
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Role:</strong> {formData.role}</Text>
                <Text><strong>Avatar:</strong> {formData.avatar}</Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Row justify="between" gap={8}>
          <Button variant="ghost" disabled={step === 1} onClick={prev}>Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={next}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleComplete(formData)}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
